@Composable
fun ConfigSection(
    title: String,
    items: List<ConfigItem>,
    onItemChange: (String, Any) -> Unit
) {
    Card(
        modifier = Modifier.fillMaxWidth(),
        elevation = CardDefaults.cardElevation(defaultElevation = 4.dp)
    ) {
        Column(
            modifier = Modifier.padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            Text(
                text = title,
                style = MaterialTheme.typography.titleMedium,
                fontWeight = FontWeight.Bold
            )
            items.forEach { item ->
                ConfigItemRow(
                    item = item,
                    onValueChange = { value -> onItemChange(item.key, value) }
                )
            }
        }
    }
}

@Composable
fun ConfigItemRow(
    item: ConfigItem,
    onValueChange: (Any) -> Unit
) {
    Row(
        modifier = Modifier.fillMaxWidth(),
        horizontalArrangement = Arrangement.SpaceBetween,
        verticalAlignment = Alignment.CenterVertically
    ) {
        Column(modifier = Modifier.weight(1f)) {
            Text(
                text = item.displayName,
                style = MaterialTheme.typography.bodyMedium,
                fontWeight = FontWeight.Medium
            )
            if (item.description.isNotEmpty()) {
                Text(
                    text = item.description,
                    style = MaterialTheme.typography.bodySmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
            }
        }
        when (item.type) {
            ConfigType.BOOLEAN -> {
                Switch(
                    checked = item.value as Boolean,
                    onCheckedChange = onValueChange
                )
            }

            ConfigType.INTEGER -> {
                OutlinedTextField(
                    value = (item.value as Int).toString(),
                    onValueChange = {
                        it.toIntOrNull()?.let { value -> onValueChange(value) }
                    },
                    modifier = Modifier.width(100.dp)
                )
            }

            ConfigType.STRING -> {
                OutlinedTextField(
                    value = item.value as String,
                    onValueChange = onValueChange,
                    modifier = Modifier.width(150.dp)
                )
            }

            ConfigType.FLOAT -> {
                OutlinedTextField(
                    value = (item.value as Float).toString(),
                    onValueChange = {
                        it.toFloatOrNull()?.let { value -> onValueChange(value) }
                    },
                    modifier = Modifier.width(100.dp)
                )
            }
        }
    }
}

