open class ItemBase {
    @PrimaryKey(autoGenerate = true)
    var id: Long = 0

    @ColumnInfo(index = true)
    open var parentId: Long = 0

    @ColumnInfo
    var position: Int = 0

    @ColumnInfo
    var itemName: String = ""

    @ColumnInfo
    var state: Int = 0

    @ColumnInfo
    var inputText: String = ""

    @ColumnInfo
    var image1: String = ""

    @ColumnInfo
    var image2: String = ""

    @ColumnInfo
    var image3: String = ""

    @ColumnInfo
    var image4: String = ""
    override fun equals(other: Any?): Boolean = other is ItemBase && other.id == id
    override fun hashCode(): Int = id.toInt()
    fun getStateStr(context: Context): String =
        when (state) {
            1 -> context.getString(R.string.house_state_good)
            2 -> context.getString(R.string.house_state_repair)
            3 -> context.getString(R.string.house_state_replace)
            else -> ""
        }

    fun getImageSize(): Int {
        var result = 0
        if (image1.isNotEmpty()) {
            result++
        }
        if (image2.isNotEmpty()) {
            result++
        }
        if (image3.isNotEmpty()) {
            result++
        }
        if (image4.isNotEmpty()) {
            result++
        }
        return result
    }

    fun buildImageList(): ArrayList<String> {
        val resultList: ArrayList<String> = ArrayList(4)
        if (image1.isNotEmpty()) {
            resultList.add(image1)
        }
        if (image2.isNotEmpty()) {
            resultList.add(image2)
        }
        if (image3.isNotEmpty()) {
            resultList.add(image3)
        }
        if (image4.isNotEmpty()) {
            resultList.add(image4)
        }
        return resultList
    }

    fun addOneImage(imagePath: String?) {
        if (imagePath.isNullOrEmpty()) {
            return
        }
        if (image1.isEmpty()) {
            image1 = imagePath
        } else if (image2.isEmpty()) {
            image2 = imagePath
        } else if (image3.isEmpty()) {
            image3 = imagePath
        } else if (image4.isEmpty()) {
            image4 = imagePath
        }
    }

    fun delOneImage(imageNum: Int) {
        when (imageNum) {
            4 -> {
                image4 = ""
            }

            3 -> {
                if (image4.isEmpty()) {
                    image3 = ""
                } else {
                    image3 = image4
                    image4 = ""
                }
            }

            2 -> {
                if (image3.isEmpty()) {
                    image2 = ""
                } else {
                    image2 = image3
                    if (image4.isEmpty()) {
                        image3 = ""
                    } else {
                        image3 = image4
                        image4 = ""
                    }
                }
            }

            1 -> {
                if (image2.isEmpty()) {
                    image1 = ""
                } else {
                    image1 = image2
                    if (image3.isEmpty()) {
                        image2 = ""
                    } else {
                        image2 = image3
                        if (image4.isEmpty()) {
                            image3 = ""
                        } else {
                            image3 = image4
                            image4 = ""
                        }
                    }
                }
            }
        }
    }
}

