        Log.i(TAG, "registerUSB");
        if (mUSBMonitor != null) {
            mUSBMonitor.register();
        }
    }

    public void unregisterUSB() {
        Log.i(TAG, "unregisterUSB");
        if (mUSBMonitor != null) {
            mUSBMonitor.destroy();
        }
