        timeWheelLayout = findViewById(R.id.wheel_picker_time_wheel);

        setCurtainEnabled(true);
        getMonthLabelView().setTextColor(0xffffffff);
        getYearLabelView().setTextColor(0xffffffff);
        getDayLabelView().setTextColor(0xffffffff);
