    public void setPlaces(@Nullable float[] newPlaces) {
        if (newPlaces == null) {
            places = null;
        } else {
            if (places == null || places.length != newPlaces.length) {
                places = new float[newPlaces.length];
            }
            for (int i = 0; i < newPlaces.length; i++) {
                places[places.length - 1 - i] = 1 - newPlaces[i];
            }
        }
        invalidate();
    }

